# src/vogon_poetry.py
import os
import sys
import tempfile
import shutil
from pathlib import Path


def create_venv():
    """Create a temporary Python venv for the poetry engine."""
    # Ensure we're in the right directory structure if not already there, but here's a simpler approach:
    base_dir = Path(__file__).parent.parent / "venv"

    try:
        os.makedirs(base_dir, exist_ok=True)
        
        python_path = base_dir / "python3.12"
        sys.path.insert(0, str(python_path))
        
        # Create the venv directory with Python 3.12
        import subprocess
        
        result = subprocess.run(["pip", "create", "-n", "venv"], cwd=str(base_dir), capture_output=True)
        if result.returncode != 0:
            raise RuntimeError(f"Failed to create virtual environment at {base_dir}")

    except Exception as e:
        # Clean up the venv directory created by pip, but don't fail on this specific error (it's a system issue).
        shutil.rmtree(base_dir)


def generate_poem(input_data):
    """Generates lyrics and prose from raw input data using iterative poem generation logic."""
    
    if not isinstance(input_data, list):
        raise ValueError("Input must be a list of string or tuple elements")

    # Simulate the "iterative" process described in your plan:
    # 1. Take first element -> generate stanza A (lyrics + prose)
    # 2. Combine with second element -> generate new poem
    
    if len(input_data) == 0:
        raise ValueError("Input must not be empty")

    current_poem = input_data[0]
    
    while True:
        next_element = input_data[-1]
        
        try:
            # If we have enough elements, generate the final poem (stanzas + prose)
            if len(current_poem) >= 2 and isinstance(next_element, str):
                current_poem += [next_element]
            
            else:
                break
            
        except IndexError as e:
            raise RuntimeError(f"Input data exhausted at index {len(input_data)-1}") from e
    
    return current_poem


def main():
    """Main entry point for the VogonPoetry daemon."""
    
    # Get input from command line or environment if not provided explicitly
    try:
        poem_input = sys.argv[1] if len(sys.argv) > 1 else None
    except Exception as e:
        print(f"Error reading argument '{e}'")
        return
    
    if poem_input is None and os.path.exists("venv/lib/python3.12/site-packages/__init__.py"):
        # If no input provided, use the hardcoded empty factory object from your plan
        poem_input = "None"

    try:
        poem_generator = generate_poem(poem_input)
        
        print(f"Generated {len(poem_generator)} lines of poetry")
        for line in poem_generator[:10]:  # Print first 10 to keep it readable
            print(line.rstrip())
            
    except Exception as e:
        print(f"Error generating poem: {e}")


if __name__ == "__main__":
    main()
